SELECT * FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
ORDER BY fetched_at DESC
LIMIT 1

SELECT * FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
  AND fetched_at >= DATEADD(DAY, -30, CURRENT_TIMESTAMP)
ORDER BY fetched_at ASC
